import { render, screen, within } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { describe, expect, it, vi } from "vitest";
import { Select } from "./Select";

const options = [
  { value: "yellow", label: "Yellow" },
  { value: "blue", label: "Blue" },
  { value: "red", label: "Red", disabled: true },
];

describe("Select", () => {
  it("opens a listbox and selects an option with pointer input", async () => {
    const user = userEvent.setup();
    const onValueChange = vi.fn();

    render(
      <Select
        name="tone"
        options={options}
        defaultValue="yellow"
        onValueChange={onValueChange}
      />,
    );

    const trigger = screen.getByRole("button", { name: /yellow/i });
    expect(trigger).toHaveAttribute("aria-haspopup", "listbox");
    expect(trigger).toHaveAttribute("aria-expanded", "false");
    expect(trigger).not.toHaveAttribute("aria-controls");
    expect(trigger).not.toHaveAttribute("aria-activedescendant");

    await user.click(trigger);

    const listbox = await screen.findByRole("listbox");
    expect(trigger).toHaveAttribute("aria-expanded", "true");
    expect(trigger).toHaveAttribute("aria-controls", listbox.id);
    expect(trigger).toHaveAttribute(
      "aria-activedescendant",
      `${listbox.id}-option-0`,
    );
    expect(within(listbox).getByRole("option", { name: "Yellow" }))
      .toHaveAttribute("aria-selected", "true");
    expect(within(listbox).getByRole("option", { name: "Blue" }))
      .toHaveAttribute("aria-selected", "false");
    expect(within(listbox).getByRole("option", { name: "Red" }))
      .toHaveAttribute("aria-disabled", "true");
    expect(within(listbox).getByRole("option", { name: "Red" }))
      .toBeDisabled();

    await user.click(screen.getByRole("option", { name: "Blue" }));

    expect(onValueChange).toHaveBeenCalledWith("blue");
    expect(screen.queryByRole("listbox")).not.toBeInTheDocument();
    expect(screen.getByDisplayValue("blue")).toHaveAttribute("name", "tone");
  });

  it("supports keyboard selection and Escape close", async () => {
    const user = userEvent.setup();
    const onValueChange = vi.fn();

    render(
      <Select
        options={options}
        defaultValue="yellow"
        onValueChange={onValueChange}
      />,
    );

    const trigger = screen.getByRole("button", { name: /yellow/i });
    trigger.focus();

    await user.keyboard("{ArrowDown}{Enter}");

    expect(onValueChange).toHaveBeenCalledWith("blue");
    expect(screen.queryByRole("listbox")).not.toBeInTheDocument();

    await user.click(screen.getByRole("button", { name: /blue/i }));
    const listbox = await screen.findByRole("listbox");
    expect(trigger).toHaveAttribute(
      "aria-activedescendant",
      `${listbox.id}-option-1`,
    );

    await user.keyboard("{Escape}");
    expect(screen.queryByRole("listbox")).not.toBeInTheDocument();
    expect(trigger).toHaveAttribute("aria-expanded", "false");
    expect(trigger).not.toHaveAttribute("aria-controls");
    expect(trigger).not.toHaveAttribute("aria-activedescendant");
  });

  it("does not open a disabled select", async () => {
    const user = userEvent.setup();

    render(<Select disabled options={options} defaultValue="yellow" />);

    const trigger = screen.getByRole("button", { name: /yellow/i });

    expect(trigger).toBeDisabled();
    expect(trigger).toHaveAttribute("aria-expanded", "false");
    expect(trigger).not.toHaveAttribute("aria-controls");

    await user.click(trigger);

    expect(screen.queryByRole("listbox")).not.toBeInTheDocument();
    expect(trigger).toHaveAttribute("aria-expanded", "false");
  });

  it("can hide the selected option indicator", async () => {
    const user = userEvent.setup();

    render(
      <Select
        options={options}
        defaultValue="yellow"
        showSelectedIndicator={false}
      />,
    );

    await user.click(screen.getByRole("button", { name: /yellow/i }));

    expect(screen.getByRole("option", { name: "Yellow" })).toHaveTextContent(
      /^Yellow$/,
    );
  });

  it("supports Home, End, and typeahead navigation", async () => {
    const user = userEvent.setup();
    const onValueChange = vi.fn();

    render(
      <Select
        options={options}
        defaultValue="yellow"
        onValueChange={onValueChange}
      />,
    );

    const trigger = screen.getByRole("button", { name: /yellow/i });
    trigger.focus();

    await user.keyboard("{End}");

    const listbox = await screen.findByRole("listbox");
    expect(trigger).toHaveAttribute(
      "aria-activedescendant",
      `${listbox.id}-option-1`,
    );

    await user.keyboard("{Home}");
    expect(trigger).toHaveAttribute(
      "aria-activedescendant",
      `${listbox.id}-option-0`,
    );

    await user.keyboard("b");
    expect(trigger).toHaveAttribute(
      "aria-activedescendant",
      `${listbox.id}-option-1`,
    );

    await user.keyboard("{Enter}");

    expect(onValueChange).toHaveBeenCalledWith("blue");
    expect(screen.queryByRole("listbox")).not.toBeInTheDocument();
    expect(screen.getByRole("button", { name: /blue/i })).toHaveFocus();
  });
});

"use client";

import { forwardRef, useEffect, useId, useMemo, useRef, useState } from "react";
import type { HTMLAttributes, KeyboardEvent, ReactNode } from "react";
import { createPortal } from "react-dom";
import {
  cn,
  composeRefs,
  disabledInteractiveStyles,
  focusVisibleStyles,
  swirskiAttrs,
} from "../../system";
import { useFloatingPosition } from "../../system/floating";
import { usePortalRoot } from "../../hooks/use-portal-root/usePortalRoot";
import SelectContent from "./SelectContent";
import type {
  SelectOption,
  SelectSize,
  SelectTone,
  SelectVariant,
} from "./select-types";
import {
  findMatchingOptionIndex,
  getEnabledIndex,
  getLastEnabledIndex,
  moveHighlight,
  optionText,
  triggerSizeStyles,
} from "./select-utils";

export type {
  SelectOption,
  SelectSize,
  SelectTone,
  SelectVariant,
} from "./select-types";

export type SelectProps = {
  options: SelectOption[];
  value?: string;
  defaultValue?: string;
  onValueChange?: (value: string) => void;
  placeholder?: string;
  disabled?: boolean;
  name?: string;
  selectedIndicator?: ReactNode;
  showSelectedIndicator?: boolean;
  triggerClassName?: string;
  contentClassName?: string;
  optionClassName?: string;
  variant?: SelectVariant;
  size?: SelectSize;
  tone?: SelectTone;
} & Omit<HTMLAttributes<HTMLDivElement>, "defaultValue" | "onChange">;

export const Select = forwardRef<HTMLDivElement, SelectProps>(function Select(
  {
    options,
    value,
    defaultValue,
    onValueChange,
    placeholder = "Select an option",
    disabled = false,
    name,
    selectedIndicator = "x",
    showSelectedIndicator = false,
    className,
    triggerClassName,
    contentClassName,
    optionClassName,
    variant = "default",
    size = "md",
    tone = "default",
    ...props
  },
  ref,
) {
  const rootRef = useRef<HTMLDivElement>(null);
  const contentRef = useRef<HTMLDivElement>(null);
  const typeaheadSearchRef = useRef("");
  const typeaheadTimeoutRef = useRef<number | null>(null);
  const portalRoot = usePortalRoot();
  const generatedId = useId();
  const [isOpen, setIsOpen] = useState(false);
  const [internalValue, setInternalValue] = useState(
    defaultValue ?? options.find((option) => !option.disabled)?.value ?? "",
  );
  const contentStyle = useFloatingPosition({
    floatingRef: contentRef,
    matchReferenceWidth: true,
    open: isOpen,
    placement: "bottom-start",
    referenceRef: rootRef,
  });
  const selectedValue = value ?? internalValue;
  const selectedIndex = options.findIndex(
    (option) => option.value === selectedValue,
  );
  const [highlightedIndex, setHighlightedIndex] = useState(
    getEnabledIndex(options, selectedIndex >= 0 ? selectedIndex : 0),
  );
  const selectedOption = useMemo(
    () => options.find((option) => option.value === selectedValue),
    [options, selectedValue],
  );
  const listboxId = `${generatedId}-listbox`;

  useEffect(() => {
    return () => {
      if (typeaheadTimeoutRef.current) {
        window.clearTimeout(typeaheadTimeoutRef.current);
      }
    };
  }, []);

  useEffect(() => {
    if (!isOpen) {
      return;
    }

    const handlePointerDown = (event: PointerEvent) => {
      const target = event.target as Node;

      if (
        !rootRef.current?.contains(target) &&
        !contentRef.current?.contains(target)
      ) {
        setIsOpen(false);
      }
    };

    window.addEventListener("pointerdown", handlePointerDown);

    return () => {
      window.removeEventListener("pointerdown", handlePointerDown);
    };
  }, [isOpen]);

  useEffect(() => {
    if (!isOpen) {
      return;
    }

    setHighlightedIndex((currentIndex) => {
      if (currentIndex >= 0 && !options[currentIndex]?.disabled) {
        return currentIndex;
      }

      return getEnabledIndex(options, selectedIndex >= 0 ? selectedIndex : 0);
    });
  }, [isOpen, options, selectedIndex]);

  useEffect(() => {
    if (!isOpen || highlightedIndex < 0) {
      return;
    }

    const option = document.getElementById(
      `${listboxId}-option-${highlightedIndex}`,
    );

    option?.scrollIntoView?.({ block: "nearest" });
  }, [highlightedIndex, isOpen, listboxId]);

  function selectValue(nextValue: string) {
    if (value === undefined) {
      setInternalValue(nextValue);
    }

    onValueChange?.(nextValue);
    clearTypeahead();
    setIsOpen(false);
  }

  function clearTypeahead() {
    typeaheadSearchRef.current = "";

    if (typeaheadTimeoutRef.current) {
      window.clearTimeout(typeaheadTimeoutRef.current);
      typeaheadTimeoutRef.current = null;
    }
  }

  function queueTypeaheadReset() {
    if (typeaheadTimeoutRef.current) {
      window.clearTimeout(typeaheadTimeoutRef.current);
    }

    typeaheadTimeoutRef.current = window.setTimeout(() => {
      typeaheadSearchRef.current = "";
      typeaheadTimeoutRef.current = null;
    }, 700);
  }

  function handleKeyDown(event: KeyboardEvent<HTMLButtonElement>) {
    if (disabled) {
      return;
    }

    if (event.key === "ArrowDown" || event.key === "ArrowUp") {
      event.preventDefault();
      setIsOpen(true);
      setHighlightedIndex((currentIndex) =>
        moveHighlight(
          options,
          currentIndex,
          event.key === "ArrowDown" ? 1 : -1,
        ),
      );
      return;
    }

    if (event.key === "Home") {
      event.preventDefault();
      setIsOpen(true);
      setHighlightedIndex(getEnabledIndex(options, 0));
      return;
    }

    if (event.key === "End") {
      event.preventDefault();
      setIsOpen(true);
      setHighlightedIndex(getLastEnabledIndex(options));
      return;
    }

    if (event.key === "Enter" || event.key === " ") {
      event.preventDefault();

      if (!isOpen) {
        setIsOpen(true);
        return;
      }

      const highlightedOption = options[highlightedIndex];

      if (highlightedOption && !highlightedOption.disabled) {
        selectValue(highlightedOption.value);
      }

      return;
    }

    if (event.key === "Escape") {
      clearTypeahead();
      setIsOpen(false);
      return;
    }

    if (
      event.key.length === 1 &&
      !event.altKey &&
      !event.ctrlKey &&
      !event.metaKey
    ) {
      event.preventDefault();

      typeaheadSearchRef.current = `${typeaheadSearchRef.current}${event.key}`;
      queueTypeaheadReset();

      const nextIndex = findMatchingOptionIndex(
        options,
        typeaheadSearchRef.current,
        highlightedIndex >= 0 ? highlightedIndex : selectedIndex,
      );

      if (nextIndex !== -1) {
        setIsOpen(true);
        setHighlightedIndex(nextIndex);
      }
    }
  }

  return (
    <div
      ref={composeRefs(rootRef, ref)}
      className={cn("relative min-w-0", className)}
      {...swirskiAttrs("select", { size, tone, variant })}
      {...props}
    >
      {name && <input type="hidden" name={name} value={selectedValue} />}

      <button
        aria-activedescendant={
          isOpen && highlightedIndex >= 0
            ? `${listboxId}-option-${highlightedIndex}`
            : undefined
        }
        aria-controls={isOpen ? listboxId : undefined}
        aria-expanded={isOpen}
        aria-haspopup="listbox"
        className={cn(
          "flex w-full items-center justify-between gap-3 border-[length:var(--sw-border-width)] border-[color:var(--sw-color-ink)] text-left font-black uppercase text-[var(--sw-color-ink)] shadow-[4px_4px_0_var(--sw-color-shadow)] outline-none transition-all duration-150 hover:translate-x-0.5 hover:translate-y-0.5 hover:shadow-[2px_2px_0_var(--sw-color-shadow)] active:translate-x-1 active:translate-y-1 disabled:bg-neutral-200 disabled:text-neutral-500 disabled:hover:shadow-[4px_4px_0_var(--sw-color-shadow)]",
          focusVisibleStyles,
          disabledInteractiveStyles,
          variant === "default" ? "bg-[var(--sw-color-surface)]" : "bg-[var(--sw-color-paper)]",
          triggerSizeStyles[size],
          triggerClassName,
        )}
        disabled={disabled}
        onClick={() => setIsOpen((currentValue) => !currentValue)}
        onKeyDown={handleKeyDown}
        type="button"
        {...swirskiAttrs("select-trigger", { size, tone, variant })}
      >
        <span className={cn(!selectedOption && "text-black/50")}>
          {selectedOption ? optionText(selectedOption) : placeholder}
        </span>
        <span
          aria-hidden="true"
          className={cn(
            "grid size-6 shrink-0 place-items-center border-2 border-[color:var(--sw-color-ink)] bg-[var(--sw-color-yellow)] leading-none transition",
            isOpen && "rotate-180",
          )}
        >
          v
        </span>
      </button>

      {isOpen &&
        portalRoot &&
        createPortal(
          <SelectContent
            contentClassName={contentClassName}
            contentStyle={contentStyle}
            contentRef={contentRef}
            highlightedIndex={highlightedIndex}
            listboxId={listboxId}
            onOptionHover={setHighlightedIndex}
            onOptionSelect={selectValue}
            optionClassName={optionClassName}
            options={options}
            selectedIndicator={selectedIndicator}
            selectedValue={selectedValue}
            showSelectedIndicator={showSelectedIndicator}
            size={size}
            tone={tone}
            variant={variant}
          />,
          portalRoot,
        )}
    </div>
  );
});

Select.displayName = "Select";

import type { CSSProperties, ReactNode, Ref } from "react";
import { cn, swirskiAttrs } from "../../system";
import type {
  SelectOption,
  SelectSize,
  SelectTone,
  SelectVariant,
} from "./select-types";
import { optionSizeStyles, optionText } from "./select-utils";

export type SelectContentProps = {
  contentClassName?: string;
  contentRef: Ref<HTMLDivElement>;
  contentStyle: CSSProperties;
  highlightedIndex: number;
  listboxId: string;
  onOptionHover: (index: number) => void;
  onOptionSelect: (value: string) => void;
  optionClassName?: string;
  options: SelectOption[];
  selectedIndicator: ReactNode;
  selectedValue: string;
  showSelectedIndicator: boolean;
  size: SelectSize;
  tone: SelectTone;
  variant: SelectVariant;
};

export default function SelectContent({
  contentClassName,
  contentRef,
  contentStyle,
  highlightedIndex,
  listboxId,
  onOptionHover,
  onOptionSelect,
  optionClassName,
  options,
  selectedIndicator,
  selectedValue,
  showSelectedIndicator,
  size,
  tone,
  variant,
}: SelectContentProps) {
  return (
    <div
      ref={contentRef}
      className={cn(
        "fixed z-[1000] max-h-64 min-w-50 overflow-y-auto border-[length:var(--sw-border-width)] border-[color:var(--sw-color-ink)] bg-[var(--sw-color-surface)] p-1 shadow-[7px_7px_0_var(--sw-color-shadow)]",
        contentClassName,
      )}
      id={listboxId}
      role="listbox"
      {...swirskiAttrs("select-content", { size, tone, variant })}
      style={contentStyle}
    >
      {options.map((option, index) => {
        const isSelected = option.value === selectedValue;
        const isHighlighted = index === highlightedIndex;

        return (
          <button
            aria-disabled={option.disabled}
            aria-selected={isSelected}
            className={cn(
              "flex w-full items-center justify-between gap-3 text-left font-black uppercase transition",
              optionSizeStyles[size],
              isHighlighted && !option.disabled && "bg-[var(--sw-color-blue)] text-white",
              isSelected && "bg-[var(--sw-color-blue)] text-white",
              option.disabled
                ? "cursor-not-allowed text-black/35"
                : "hover:bg-[var(--sw-color-blue)] hover:text-white",
              optionClassName,
            )}
            disabled={option.disabled}
            id={`${listboxId}-option-${index}`}
            key={option.value}
            onClick={() => onOptionSelect(option.value)}
            onMouseEnter={() => {
              if (!option.disabled) {
                onOptionHover(index);
              }
            }}
            role="option"
            type="button"
            {...swirskiAttrs("select-option", { size, tone, variant })}
          >
            <span>{optionText(option)}</span>

            {showSelectedIndicator && isSelected && (
              <span aria-hidden="true">{selectedIndicator}</span>
            )}
          </button>
        );
      })}
    </div>
  );
}

export { Select } from "./Select";
export type {
  SelectOption,
  SelectProps,
  SelectSize,
  SelectTone,
  SelectVariant,
} from "./Select";

import type { ReactNode } from "react";

export type SelectVariant = "default" | "filled";
export type SelectSize = "sm" | "md" | "lg";
export type SelectTone = "default";

export type SelectOption = {
  value: string;
  label?: ReactNode;
  disabled?: boolean;
};

import type { SelectOption, SelectSize } from "./select-types";

export const triggerSizeStyles: Record<SelectSize, string> = {
  sm: "min-h-10 px-3 py-1.5 text-xs",
  md: "min-h-12 px-3 py-2 text-sm",
  lg: "min-h-14 px-4 py-3 text-base",
};

export const optionSizeStyles: Record<SelectSize, string> = {
  sm: "min-h-9 px-2 py-1.5 text-xs",
  md: "min-h-10 px-3 py-2 text-xs",
  lg: "min-h-12 px-4 py-3 text-sm",
};

export function optionText(option: SelectOption) {
  return option.label ?? option.value;
}

function optionSearchText(option: SelectOption) {
  if (typeof option.label === "string" || typeof option.label === "number") {
    return String(option.label);
  }

  return option.value;
}

export function getEnabledIndex(options: SelectOption[], startIndex = 0) {
  const directIndex = options.findIndex(
    (option, index) => index >= startIndex && !option.disabled,
  );

  if (directIndex !== -1) {
    return directIndex;
  }

  return options.findIndex((option) => !option.disabled);
}

export function getLastEnabledIndex(options: SelectOption[]) {
  for (let index = options.length - 1; index >= 0; index -= 1) {
    if (!options[index]?.disabled) {
      return index;
    }
  }

  return -1;
}

export function moveHighlight(
  options: SelectOption[],
  currentIndex: number,
  direction: 1 | -1,
) {
  if (!options.some((option) => !option.disabled)) {
    return currentIndex;
  }

  let nextIndex = currentIndex;

  for (let count = 0; count < options.length; count += 1) {
    nextIndex = (nextIndex + direction + options.length) % options.length;

    if (!options[nextIndex]?.disabled) {
      return nextIndex;
    }
  }

  return currentIndex;
}

export function findMatchingOptionIndex(
  options: SelectOption[],
  search: string,
  currentIndex: number,
) {
  if (!search || !options.length) {
    return -1;
  }

  const normalizedSearch = search.toLowerCase();
  const isRepeatedCharacterSearch =
    normalizedSearch.length > 1 &&
    normalizedSearch.split("").every((char) => char === normalizedSearch[0]);
  const lookup = isRepeatedCharacterSearch
    ? normalizedSearch[0]
    : normalizedSearch;

  for (let offset = 1; offset <= options.length; offset += 1) {
    const index = (currentIndex + offset + options.length) % options.length;
    const option = options[index];

    if (
      option &&
      !option.disabled &&
      optionSearchText(option).toLowerCase().startsWith(lookup)
    ) {
      return index;
    }
  }

  return -1;
}
